nsform:uppercase}.table td{padding:14px 18px;font-size:.75rem}.company{display:flex;align-items:center;gap:11px}.company-mark{width:37px;height:37px;border-radius:10px;display:grid;place-items:center;background:linear-gradient(135deg,#173d39,#1b4c59);color:#6ee7b7;font-weight:800}.company-name{font-weight:800;color:#f4f7fc}.meta{font-size:.62rem;color:#8391a6;margin-top:3px}.country{display:flex;align-items:center;gap:8px}.country img{width:29px;height:22px;object-fit:cover;border-radius:5px;border:1px solid #ffffff18}.contact{color:#b9c7d9}.contact a{display:block;color:#7dd3fc;text-decoration:none;font-size:.66rem;margin-top:3px}.status{display:inline-flex;align-items:center;gap:6px;padding:6px 9px;border-radius:99px;font-size:.62rem;font-weight:800}.status.active{background:#10b98118;color:#6ee7b7}.status.inactive{background:#ef444418;color:#fca5a5}.mail-btn{width:32px;height:32px;display:grid;place-items:center;margin-left:auto;border:1px solid #30435f;border-radius:8px;background:#17263d;color:#b8c5d8;text-decoration:none}.mail-btn:hover{color:#fff;border-color:#34d399}.empty{padding:50px;text-align:center;color:#8290a5}.pagination-wrap{padding:15px 22px;border-top:1px solid var(--line)}.pagination{margin:0;--bs-pagination-bg:#14243c;--bs-pagination-border-color:#2c405c;--bs-pagination-color:#a9b8cd;--bs-pagination-hover-bg:#1b2d48;--bs-pagination-hover-color:#fff;--bs-pagination-active-bg:#059669;--bs-pagination-active-border-color:#059669}.mobile-menu{display:none}@media(max-width:991px){.sidebar{transform:translateX(-100%);transition:.25s}.sidebar.open{transform:none;box-shadow:30px 0 80px #000b}.main{margin-left:0}.mobile-menu{display:grid}.content{padding:20px}.topbar{padding:0 20px}.hero{padding:25px}}@media(max-width:575px){.content{padding:14px}.hero h1{font-size:1.55rem}.toolbar{align-items:flex-start;flex-direction:column}.search{width:100%}}
